/**
 * @summary Get recently updated cases
 */
export const getGetRecentCasesUrl = (params?: GetRecentCasesParams) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/cases/recent?${stringifiedParams}`
    : `/api/cases/recent`;
};

export const getRecentCases = async (
  params?: GetRecentCasesParams,
  options?: RequestInit,
): Promise<CaseSummary[]> => {
  return customFetch<CaseSummary[]>(getGetRecentCasesUrl(params), {
    ...options,
    method: "GET",
  });
};

export const getGetRecentCasesQueryKey = (params?: GetRecentCasesParams) => {
  return [`/api/cases/recent`, ...(params ? [params] : [])] as const;
};

export const getGetRecentCasesQueryOptions = <
  TData = Awaited<ReturnType<typeof getRecentCases>>,
  TError = ErrorType<unknown>,
>(
  params?: GetRecentCasesParams,
  options?: {
    query?: UseQueryOptions<
      Awaited<ReturnType<typeof getRecentCases>>,
      TError,
      TData
    >;
    request?: SecondParameter<typeof customFetch>;
  },
) => {
  const { query: queryOptions, request: requestOptions } = options ?? {};

  const queryKey = queryOptions?.queryKey ?? getGetRecentCasesQueryKey(params);

  const queryFn: QueryFunction<Awaited<ReturnType<typeof getRecentCases>>> = ({
    signal,
  }) => getRecentCases(params, { signal, ...requestOptions });

  return { queryKey, queryFn, ...queryOptions } as UseQueryOptions<
    Awaited<ReturnType<typeof getRecentCases>>,
    TError,
    TData
  > & { queryKey: QueryKey };
};

